7	  it("quote with empty item list returns premium 5 G (processing fee only)", () => {
8	    const result = runScenario({
9	      customer: { yearsWithMHPCO: 0 },
10	      steps: [{ op: "quote", items: [] }],
11	    });
12	    expect(result).toEqual({ results: [{ premium: 5 }] });
13	  });
14	
15	  // --- Base premiums for single main items (with 5 G fee, newcomer 10% first-insurance) ---
