17	  // To keep the simplest tests truly simple, we test the base-premium examples through
18	  // long-standing-customer follow-up scenarios where only the base + fee apply.
19	  // We test base premiums first via the spec examples about building blocks (which are
20	  // explicitly described as "base premiums"). So we start there.
21	
22	  // --- Building block of 3 alike components (base premium examples from spec) ---
23	  it("2 runes have base premium 50 G (2 x 25 G, no block)", () => {
24	    // 50 base + 5 first-insurance (10% of 50) + 5 fee = 60
25	    const result = runScenario({
26	      customer: { yearsWithMHPCO: 0 },
27	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
28	    });
29	    expect(result).toEqual({ results: [{ premium: 60 }] });
30	  });
31	  it("3 runes have base premium 60 G (block applies)", () => {
32	    // 60 base + 6 first-insurance (10% of 60) + 5 fee = 71
33	    const result = runScenario({
34	      customer: { yearsWithMHPCO: 0 },
35	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
36	    });
37	    expect(result).toEqual({ results: [{ premium: 71 }] });
38	  });
39	  it("4 runes have base premium 100 G (no block — block requires exactly 3)", () => {
40	    // 100 base + 10 first-insurance + 5 fee = 115
41	    const result = runScenario({
42	      customer: { yearsWithMHPCO: 0 },
43	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
