1	import { runScenario } from "./claim-office.js";
2	
3	async function readAllStdin(): Promise<string> {
4	  const chunks: Buffer[] = [];
5	  for await (const chunk of process.stdin) {
6	    chunks.push(chunk as Buffer);
7	  }
8	  return Buffer.concat(chunks).toString("utf-8");
9	}
10	
11	try {
12	  const input = await readAllStdin();
13	  const scenario = JSON.parse(input);
14	  const result = runScenario(scenario);
15	  process.stdout.write(JSON.stringify(result));
16	} catch (err) {
17	  process.stderr.write((err as Error).message);
18	  process.exit(1);
19	}
